// The Birthday Dossier — on-device numerology, star charts and horoscopes.
//
// House rules, same as the number generator downstairs:
//   • The FACTS are real. Star sign dates, Chinese zodiac years (lunar-new-year
//     accurate), birthstones, birth flowers — all correct, because people who
//     care about these things deserve to see them done properly.
//   • The MEANINGS are decorative. All of them. The horoscope is generated by
//     arithmetic wearing a dressing gown.
//   • Nothing leaves the device. No network, no analytics payloads, nothing.
//     A test enforces this. The cosmos operates strictly offline.

import { track } from '../services/analytics';

const LOCAL_KEY = 'dossier-prefs';

/* ======================================================================
   REAL FACTS (kept accurate on purpose)
   ====================================================================== */

interface StarSign {
	name: string;
	glyph: string;
	from: readonly [number, number]; // month, day (inclusive start)
	blurb: string;
}

// Western tropical dates, conventional boundaries. Ordered from Capricorn so
// lookup is a simple scan (Capricorn wraps the year end).
const STAR_SIGNS: readonly StarSign[] = [
	{ name: 'Capricorn', glyph: '♑', from: [12, 22], blurb: 'Climbing something as we speak. Probably a career.' },
	{ name: 'Aquarius', glyph: '♒', from: [1, 20], blurb: 'Ahead of their time, and slightly to the left of it.' },
	{ name: 'Pisces', glyph: '♓', from: [2, 19], blurb: 'Swimming in both directions at once, elegantly.' },
	{ name: 'Aries', glyph: '♈', from: [3, 21], blurb: 'First into everything, including this sentence.' },
	{ name: 'Taurus', glyph: '♉', from: [4, 20], blurb: 'Immovable object; negotiable if snacks are involved.' },
	{ name: 'Gemini', glyph: '♊', from: [5, 21], blurb: 'Two for the price of one. Both of you are welcome here.' },
	{ name: 'Cancer', glyph: '♋', from: [6, 21], blurb: 'Armoured exterior, gooey centre. The cosmos respects the shell.' },
	{ name: 'Leo', glyph: '♌', from: [7, 23], blurb: 'Main character energy, officially licensed.' },
	{ name: 'Virgo', glyph: '♍', from: [8, 23], blurb: 'Has already spotted the typo in this dossier.' },
	{ name: 'Libra', glyph: '♎', from: [9, 23], blurb: 'Perfectly balanced. Took four hours to decide that.' },
	{ name: 'Scorpio', glyph: '♏', from: [10, 23], blurb: 'Intense. The stars would say more, but they’re a little scared.' },
	{ name: 'Sagittarius', glyph: '♐', from: [11, 22], blurb: 'Currently planning a trip. The arrow has already left.' }
];

function starSignFor(month: number, day: number): StarSign {
	// walk backwards through start dates; first one we're on/after wins
	for (let i = STAR_SIGNS.length - 1; i >= 0; i--) {
		const [m, d] = STAR_SIGNS[i].from;
		if (month > m || (month === m && day >= d)) return STAR_SIGNS[i];
	}
	return STAR_SIGNS[0]; // Jan 1–19 → Capricorn (wrapped)
}

