// element cycle by the zodiac year's last digit (also bounded by CNY)
const ELEMENTS: Record<number, string> = {
	0: 'Metal', 1: 'Metal', 2: 'Water', 3: 'Water', 4: 'Wood',
	5: 'Wood', 6: 'Fire', 7: 'Fire', 8: 'Earth', 9: 'Earth'
};

/** The zodiac year a Gregorian date belongs to (lunar-new-year accurate). */
function zodiacYearFor(date: Date): number {
	const y = date.getFullYear();
	const cny = CNY_DATES[y - CNY_BASE_YEAR];
	if (!cny) return y; // outside table — degrade to calendar year
	// compare LOCAL date parts — toISOString() is UTC and can drift a day
	const iso = `${y}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`;
	return iso < cny ? y - 1 : y;
}

function chineseZodiacFor(date: Date): { animal: (typeof ZODIAC_ANIMALS)[number]; element: string; year: number } {
	const year = zodiacYearFor(date);
	const idx = (((year - 1924) % 12) + 12) % 12; // 1924 = Rat
	return { animal: ZODIAC_ANIMALS[idx], element: ELEMENTS[year % 10], year };
}

