/* ======================================================================
   NUMEROLOGY (deterministic; the numbers still don't know they're being judged)
   ====================================================================== */

// classic reduction, preserving the "master numbers" — numerology tradition
// says 11, 22 and 33 are exempt from arithmetic, which is a superb rule
function reduceKeepMasters(n: number): number {
	while (n > 9 && n !== 11 && n !== 22 && n !== 33) {
		let s = 0;
		for (const d of String(n)) s += Number(d);
		n = s;
	}
	return n;
}

export function lifePath(date: Date): number {
	const digits = `${date.getFullYear()}${String(date.getMonth() + 1).padStart(2, '0')}${String(date.getDate()).padStart(2, '0')}`;
	let s = 0;
	for (const d of digits) s += Number(d);
	return reduceKeepMasters(s);
}

// Pythagorean letter values: A=1..I=9, J=1..R=9, S=1..Z=8
export function nameNumber(name: string): number {
	let s = 0;
	for (const ch of name.toUpperCase()) {
		const c = ch.charCodeAt(0);
		if (c >= 65 && c <= 90) s += ((c - 65) % 9) + 1;
	}
	return s ? reduceKeepMasters(s) : 0;
}

