export interface Horoscope {
	omen: string;
	hedge: string;
	advice: string;
	luckyObject: string;
	luckyTime: string;
}

/** Deterministic per sign per day — everyone sharing your sign shares your
 *  fate today, which is exactly how this industry has always worked. */
export function dailyHoroscope(signIndex: number, dayIndex: number): Horoscope {
	const rng = mulberry32((signIndex + 1) * 0x9e3779b9 + dayIndex);
	const pick = <T>(arr: readonly T[]): T => arr[Math.floor(rng() * arr.length)];
	const h = Math.floor(rng() * 24);
	const m = Math.floor(rng() * 60);
	return {
		omen: pick(OMENS),
		hedge: pick(HEDGES),
		advice: pick(ADVICE),
		luckyObject: pick(LUCKY_OBJECTS),
		luckyTime: `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`
	};
}

/* ======================================================================
   THE DOSSIER ITSELF
   ====================================================================== */

interface SavedPrefs {
	dob?: string;
	name?: string;
}

export function initDossier(opts: { onFirstDossier?: () => void } = {}): void {
	const root = document.getElementById('luck-dossier');
	const dobInput = document.getElementById('dossier-dob') as HTMLInputElement | null;
	const nameInput = document.getElementById('dossier-name') as HTMLInputElement | null;
	const goBtn = document.getElementById('dossier-go') as HTMLButtonElement | null;
	const burnBtn = document.getElementById('dossier-burn') as HTMLButtonElement | null;
	const out = document.getElementById('dossier-out');
	if (!root || !dobInput || !nameInput || !goBtn || !burnBtn || !out) return;

	// sensible bounds: the table starts in 1920; the future has no birthdays yet
	dobInput.min = '1920-01-01';
	dobInput.max = new Date().toISOString().slice(0, 10);

	let everCompiled = false;
	try {
		const saved = JSON.parse(localStorage.getItem(LOCAL_KEY) || '{}') as SavedPrefs;
		if (typeof saved.dob === 'string' && saved.dob) {
			dobInput.value = saved.dob;
			if (typeof saved.name === 'string') nameInput.value = saved.name.slice(0, 80);
			everCompiled = true;
		}
	} catch { /* corrupt prefs — the cosmos starts a fresh file */ }

	const row = (label: string, value: string, note?: string): HTMLElement => {
		const li = document.createElement('li');
		li.className = 'dossier-row';
		const dt = document.createElement('span');
		dt.className = 'dossier-key';
		dt.textContent = label;
		const dd = document.createElement('span');
		dd.className = 'dossier-value';
		dd.textContent = value;
		li.append(dt, dd);
		if (note) {
			const small = document.createElement('span');
			small.className = 'dossier-note';
			small.textContent = note;
			li.appendChild(small);
		}
		return li;
	};

	function render(): boolean {
		const dob = dobInput!.value;
		if (!dob) return false;
		const date = new Date(`${dob}T12:00:00`); // noon dodges TZ edges
		if (Number.isNaN(+date) || dob < dobInput!.min || dob > dobInput!.max) return false;
		const name = nameInput!.value.trim().slice(0, 80);

		const month = date.getMonth(); // 0-based
		const sign = starSignFor(month + 1, date.getDate());
		const zodiac = chineseZodiacFor(date);
		const lp = lifePath(date);
		const nn = name ? nameNumber(name) : 0;
		const signIdx = STAR_SIGNS.indexOf(sign);
		const scope = dailyHoroscope(signIdx, Math.floor(Date.now() / 86400000));

		out!.textContent = '';
		const card = document.createElement('div');
		card.className = 'dossier-card';

		const h = document.createElement('h3');
		h.className = 'dossier-title';
		h.textContent = `OFFICIAL LUCK DOSSIER — ${name ? name.toUpperCase() : 'THE BEARER'}`;
		card.appendChild(h);

		const list = document.createElement('ul');
		list.className = 'dossier-list';
		list.append(
			row('Star sign', `${sign.glyph} ${sign.name}`, sign.blurb),
			row('Chinese zodiac', `${zodiac.animal.glyph} ${zodiac.element} ${zodiac.animal.name} (${zodiac.year})`, zodiac.animal.blurb),
			row('Birthstone', BIRTHSTONES[month], 'Wearing it is optional; the stone doesn’t mind either way.'),
			row('Birth flower', BIRTH_FLOWERS[month], 'Botanically real. Cosmically decorative.'),
			row('Life path', String(lp), NUMBER_MEANINGS[lp])
		);
		if (nn) list.appendChild(row('Name number', String(nn), `${NUMBER_MEANINGS[nn]} The letters knew before you did.`));
		card.appendChild(list);

		const scopeEl = document.createElement('p');
		scopeEl.className = 'dossier-scope';
		scopeEl.textContent = `TODAY’S FORECAST — ${scope.omen} ${scope.hedge} ${scope.advice}`;
		card.appendChild(scopeEl);

		const lucky = document.createElement('p');
		lucky.className = 'dossier-lucky';
		lucky.textContent = `Lucky object: ${scope.luckyObject}. Lucky time: ${scope.luckyTime}.`;
		card.appendChild(lucky);

		const share = document.createElement('p');
		share.className = 'dossier-small';
		share.textContent = `This forecast is shared with everyone born under ${sign.name}. Fortune-wise, you’re a co-op.`;
		card.appendChild(share);

		out!.appendChild(card);
		burnBtn!.hidden = false;
		return true;
	}

	goBtn.addEventListener('click', () => {
		if (!render()) {
			out!.textContent = '';
			const p = document.createElement('p');
			p.className = 'dossier-small';
			p.textContent = 'The cosmos needs a real birthday to work with. It checked twice.';
			out!.appendChild(p);
			return;
		}
		try {
			localStorage.setItem(LOCAL_KEY, JSON.stringify({ dob: dobInput.value, name: nameInput.value.trim().slice(0, 80) }));
		} catch { /* storage full — the dossier lives for this visit only */ }
		// usage signal only — the payload is deliberately empty. No birthday, no
		// name, no sign, nothing derived from them. A test enforces this.
		track('dossier_generated');
		if (!everCompiled) {
			everCompiled = true;
			try {
				opts.onFirstDossier?.(); // charm ceremony needs the WebGL scene…
			} catch { /* …but the dossier itself never depends on it */ }
		}
	});

	burnBtn.addEventListener('click', () => {
		localStorage.removeItem(LOCAL_KEY);
		dobInput.value = '';
		nameInput.value = '';
		out!.textContent = '';
		const p = document.createElement('p');
		p.className = 'dossier-small';
		p.textContent = 'Dossier burned. The cosmos has already forgotten you were ever born. (So has this device.)';
		out!.appendChild(p);
		burnBtn.hidden = true;
		track('dossier_burned'); // again: event only, no payload
	});

	// a returning visitor's dossier reappears without ceremony (or analytics)
	if (everCompiled) render();
}
